sử dụng tương tự code này để tạo logo chính thức cho website của công Ty TNHH Hải Lam Engineering & Construction

 <script>
      tailwind.config = {
        theme: {
          extend: {
            fontFamily: {
              sans: ['Inter', 'sans-serif'],
            },
            colors: {
              brand: {
                50: '#f2f7f5',
                100: '#e0ece6',
                200: '#c2dacd',
                300: '#9dbfb0',
                400: '#759f8e',
                500: '#527f6e',
                600: '#3e6355',
                700: '#335044',
                800: '#2F423B', // User provided Dark Green
                900: '#263630',
                950: '#131c18',
              },
              // Remapped "Accent" to Engineering Red for strong actions/buttons (matches Logo)
              accent: {
                500: '#ef4444',
                600: '#dc2626', // Standard Red
                700: '#b91c1c',
              },
              // New "Neon" color for Tech/Signal highlights
              neon: {
                400: '#3af566',
                500: '#0AE340', // User provided Bright Green
                600: '#00c738',
              }
            },
            animation: {
              'blob': 'blob 7s infinite',
            },
            keyframes: {
              blob: {
                '0%': { transform: 'translate(0px, 0px) scale(1)' },
                '33%': { transform: 'translate(30px, -50px) scale(1.1)' },
                '66%': { transform: 'translate(-20px, 20px) scale(0.9)' },
                '100%': { transform: 'translate(0px, 0px) scale(1)' },
              }
            }
          }
        }
      }
    </script>
